 209→const darkenColor = (hex, amount = 0.15) => {
 210→    const raw = hex?.replace("#", "") || "fff4a8";
 211→    const num = parseInt(raw.length === 3 ? raw.split("").map((c) => c + c).join("") : raw, 16);
 212→    const r = Math.max(0, Math.round(((num >> 16) & 255) * (1 - amount)));
 213→    const g = Math.max(0, Math.round(((num >> 8) & 255) * (1 - amount)));
 214→    const b = Math.max(0, Math.round((num & 255) * (1 - amount)));
 215→    return `rgb(${r},${g},${b})`;
 216→};
