 356→const FreedomWallPage = () => {
 357→    const {session, user, openAuthModal} = useAuth();
 358→    const queryClient = useQueryClient();
 359→    const shellRef = useRef(null);
 360→    const draftDoodleRef = useRef([]);
 361→    const [shellWidth, setShellWidth] = useState(980);
 362→    const [activeTool, setActiveTool] = useState("doodle");
 363→    const [doodleColor, setDoodleColor] = useState("#5f92ff");
 364→    const [doodleSize, setDoodleSize] = useState(3.2);
 365→    const [draftDoodlePoints, setDraftDoodlePoints] = useState([]);
 366→    const [isDrawing, setIsDrawing] = useState(false);
 367→    const [selectedSticker, setSelectedSticker] = useState("dog");
 368→    const [wallError, setWallError] = useState(null);
 369→    const [selectedStamp, setSelectedStamp] = useState("heart");
 370→    const [selectedItemId, setSelectedItemId] = useState(null);
 371→    const [draftNote, setDraftNote] = useState(null);
 372→    const [draftSticker, setDraftSticker] = useState(null);
 373→    const [draftStamp, setDraftStamp] = useState(null);
 374→    const [noteEditor, setNoteEditor] = useState({
 375→        text: "",
 376→        fontFamily: "Arial",
 377→        fontStyle: "normal",
 378→        fontColor: "#1f2937",
 379→        bgColor: "#fff4a8",
 380→        fontSize: 16
 381→    });
 382→
 383→    const authToken = session?.access_token || null;
 384→    const currentUser = user?.userData?.[0] || null;
 385→    const currentUserId = currentUser?.id || null;
 386→    const canWrite = Boolean(currentUserId);
 387→
 388→    const {
 389→        data: activeWeekData,
 390→        isLoading: isWeekLoading,
 391→        error: weekError
 392→    } = useQuery({
 393→        queryKey: ["freedomWallCurrentWeek"],
 394→        queryFn: () => getCurrentFreedomWallWeek(authToken),
 395→        refetchOnWindowFocus: true,
 396→        staleTime: 30 * 1000
 397→    });
 398→
 399→    const activeWeek = activeWeekData?.week || null;
 400→    const weekId = activeWeek?.id || null;
 401→
 402→    const itemsQueryKey = useMemo(() => ["freedomWallItems", weekId], [weekId]);
 403→
 404→    const {
 405→        data: itemsData,
 406→        isLoading: isItemsLoading
 407→    } = useQuery({
 408→        queryKey: itemsQueryKey,
 409→        queryFn: () => getFreedomWallItems(weekId, {limit: 400}, authToken),
 410→        enabled: Boolean(weekId),
 411→        refetchOnWindowFocus: false,
 412→        staleTime: 20 * 1000
 413→    });
 414→
 415→    useEffect(() => {
 416→        const updateShellWidth = () => {
 417→            const nextWidth = shellRef.current?.clientWidth || 980;
 418→            setShellWidth(nextWidth);
 419→        };
 420→
 421→        updateShellWidth();
 422→        window.addEventListener("resize", updateShellWidth);
 423→
 424→        let resizeObserver = null;
 425→        if(typeof ResizeObserver !== "undefined" && shellRef.current){
 426→            resizeObserver = new ResizeObserver(updateShellWidth);
 427→            resizeObserver.observe(shellRef.current);
 428→        }
 429→
 430→        return () => {
 431→            window.removeEventListener("resize", updateShellWidth);
 432→            if(resizeObserver){
 433→                resizeObserver.disconnect();
 434→            }
 435→        };
 436→    }, []);
 437→
 438→    const stageWidth = useMemo(() => clamp(shellWidth - 12, 280, WALL_MAX_WIDTH), [shellWidth]);
 439→    const stageHeight = useMemo(() => clamp(Math.round(stageWidth * 0.64), WALL_MIN_HEIGHT, WALL_MAX_HEIGHT), [stageWidth]);
 440→
 441→    const sortedItems = useMemo(() => sortItemsByZIndex(itemsData?.data || []), [itemsData?.data]);
 442→    const maxZIndex = useMemo(() => {
 443→        if(!sortedItems.length){
 444→            return 0;
 445→        }
 446→        return sortedItems.reduce((maxValue, item) => Math.max(maxValue, Number(item?.z_index) || 0), 0);
 447→    }, [sortedItems]);
 448→
 449→    const selectedItem = useMemo(() => {
 450→        if(!selectedItemId){
 451→            return null;
 452→        }
 453→        return sortedItems.find((item) => String(item?.id) === String(selectedItemId)) || null;
 454→    }, [selectedItemId, sortedItems]);
 455→
 456→    const selectedNote = useMemo(() => (
 457→        selectedItem?.item_type === "note" ? selectedItem : null
 458→    ), [selectedItem]);
 459→
 460→    const selectedItemCanEdit = Boolean(selectedItem && currentUserId && String(selectedItem.user_id) === String(currentUserId));
 461→
 462→    useEffect(() => {
 463→        if(!selectedNote){
 464→            return;
 465→        }
 466→
 467→        const payload = selectedNote.payload || {};
 468→        setNoteEditor({
 469→            text: payload.text || "",
 470→            fontFamily: payload.fontFamily || "Arial",
 471→            fontStyle: NOTE_STYLE_OPTIONS.includes(payload.fontStyle) ? payload.fontStyle : "normal",
 472→            fontColor: payload.fontColor || "#1f2937",
 473→            bgColor: payload.bgColor || "#fff4a8",
 474→            fontSize: clamp(Number(payload.fontSize) || 16, 10, 64)
 475→        });
 476→    }, [selectedNote]);
 477→
 478→    useEffect(() => {
 479→        if(activeTool !== "note"){
 480→            setDraftNote(null);
 481→        }
 482→        if(activeTool !== "sticker"){
 483→            setDraftSticker(null);
 484→        }
 485→        if(activeTool !== "stamp"){
 486→            setDraftStamp(null);
 487→        }
 488→    }, [activeTool]);
 489→
 490→    const setItemsCache = useCallback((updater) => {
 491→        if(!weekId){
 492→            return;
 493→        }
 494→
 495→        queryClient.setQueryData(itemsQueryKey, (old) => {
 496→            const previousItems = Array.isArray(old?.data) ? old.data : [];
 497→            const nextItems = sortItemsByZIndex(updater(previousItems));
 498→            return {
 499→                ...(old || {}),
 500→                data: nextItems,
 501→                hasMore: false,
 502→                nextCursor: null
 503→            };
 504→        });
 505→    }, [itemsQueryKey, queryClient, weekId]);
 506→
 507→    const createItemMutation = useMutation({
 508→        mutationFn: ({payload}) => createFreedomWallItem(authToken, payload),
 509→        onMutate: async({payload}) => {
 510→            const optimisticId = `optimistic-${Date.now()}-${Math.random().toString(36).slice(2, 8)}`;
 511→            const optimisticItem = {
 512→                id: optimisticId,
 513→                week_id: payload.weekId,
 514→                user_id: currentUserId,
 515→                item_type: payload.itemType,
 516→                payload: payload.payload,
 517→                z_index: payload.zIndex || 0,
 518→                created_at: new Date().toISOString(),
 519→                updated_at: new Date().toISOString(),
 520→                deleted_at: null,
 521→                users: currentUser ? {
 522→                    id: currentUser.id,
 523→                    name: currentUser.name,
 524→                    image_url: currentUser.image_url,
 525→                    badge: currentUser.badge
 526→                } : null
 527→            };
 528→
 529→            setItemsCache((items) => [...items, optimisticItem]);
 530→            return {optimisticId: optimisticId};
 531→        },
 532→        onSuccess: (response, _variables, context) => {
 533→            const createdItem = response?.item;
 534→            if(!createdItem?.id){
 535→                return;
 536→            }
 537→
 538→            setItemsCache((items) => {
 539→                const withoutOptimistic = context?.optimisticId
 540→                    ? removeById(items, context.optimisticId)
 541→                    : items;
 542→                return upsertById(withoutOptimistic, createdItem);
 543→            });
 544→        },
 545→        onError: (error, variables, context) => {
 546→            console.error("Freedom Wall create error:", error, "variables:", variables);
 547→            if(context?.optimisticId){
 548→                setItemsCache((items) => removeById(items, context.optimisticId));
 549→            }
 550→            const message = error?.message || error?.error || "Failed to place item";
 551→            setWallError(message);
 552→            setTimeout(() => setWallError((prev) => prev === message ? null : prev), 4000);
 553→        }
 554→    });
 555→
 556→    const updateItemMutation = useMutation({
 557→        mutationFn: ({itemId, payload}) => updateFreedomWallItem(authToken, itemId, payload),
 558→        onMutate: async({itemId, payload}) => {
 559→            let previousItem = null;
 560→            setItemsCache((items) => {
 561→                previousItem = items.find((item) => String(item?.id) === String(itemId)) || null;
 562→                if(!previousItem){
 563→                    return items;
 564→                }
 565→
 566→                return items.map((item) => {
 567→                    if(String(item?.id) !== String(itemId)){
 568→                        return item;
 569→                    }
 570→
 571→                    const mergedPayload = payload?.payload !== undefined
 572→                        ? {...(item?.payload || {}), ...(payload.payload || {})}
 573→                        : item?.payload;
 574→
 575→                    return {
 576→                        ...item,
 577→                        payload: mergedPayload,
 578→                        z_index: payload?.zIndex !== undefined ? payload.zIndex : item?.z_index
 579→                    };
 580→                });
 581→            });
 582→            return {previousItem: previousItem};
 583→        },
 584→        onSuccess: (response) => {
 585→            const updatedItem = response?.item;
 586→            if(!updatedItem?.id){
 587→                return;
 588→            }
 589→
 590→            setItemsCache((items) => upsertById(items, updatedItem));
 591→        },
 592→        onError: (_error, variables, context) => {
 593→            if(!context?.previousItem){
 594→                return;
 595→            }
 596→
 597→            setItemsCache((items) => upsertById(items, context.previousItem));
 598→            if(variables?.itemId){
 599→                setSelectedItemId(String(variables.itemId));
