                                            isSelected={isSelected}
                                            onSelect={handleSelectItem}
                                            onDragEnd={(event) => moveItemFromDrag(item, event)}
                                        />
                                    );
                                }

                                if(item?.item_type === "stamp"){
                                    return (
                                        <StampNode
                                            key={item.id}
                                            item={item}
                                            stageWidth={stageWidth}
                                            stageHeight={stageHeight}
                                            canEdit={canEditItem}
                                            isSelected={isSelected}
                                            onSelect={handleSelectItem}
                                            onDragEnd={(event) => moveItemFromDrag(item, event)}
                                        />
                                    );
                                }

                                if(item?.item_type === "note"){
                                    return (
                                        <NoteNode
                                            key={item.id}
                                            item={item}
                                            stageWidth={stageWidth}
                                            stageHeight={stageHeight}
                                            canEdit={canEditItem}
                                            isSelected={isSelected}
                                            onSelect={handleSelectItem}
                                            onDragEnd={(event) => moveItemFromDrag(item, event)}
                                        />
                                    );
                                }

                                return null;
                            })}

                            {draftSticker && (
                                <StickerNode
                                    item={{payload: draftSticker}}
                                    stageWidth={stageWidth}
                                    stageHeight={stageHeight}
                                    canEdit={true}
                                    isSelected={false}
                                    isDraft={true}
                                    onSelect={() => {}}
                                    onDragEnd={(event) => {
                                        const node = event?.target;
                                        if(!node) return;
                                        setDraftSticker((prev) => ({
                                            ...prev,
                                            x: clamp(node.x() / stageWidth, 0, 1),
                                            y: clamp(node.y() / stageHeight, 0, 1)
                                        }));
                                    }}
                                />
                            )}

                            {draftStamp && (
                                <StampNode
                                    item={{payload: draftStamp}}
                                    stageWidth={stageWidth}
                                    stageHeight={stageHeight}
                                    canEdit={true}
                                    isSelected={false}
                                    isDraft={true}
                                    onSelect={() => {}}
                                    onDragEnd={(event) => {
                                        const node = event?.target;
                                        if(!node) return;
                                        setDraftStamp((prev) => ({
                                            ...prev,
                                            x: clamp(node.x() / stageWidth, 0, 1),
                                            y: clamp(node.y() / stageHeight, 0, 1)
                                        }));
                                    }}
                                />
                            )}

                            {draftNote && (
                                <NoteNode
                                    item={{payload: draftNote}}
                                    stageWidth={stageWidth}
                                    stageHeight={stageHeight}
                                    canEdit={true}
                                    isSelected={false}
                                    isDraft={true}
                                    onSelect={() => {}}
                                    onDragEnd={(event) => {
                                        const node = event?.target;
                                        if(!node) return;
                                        setDraftNote((prev) => ({
                                            ...prev,
                                            x: clamp(node.x() / stageWidth, 0, 1),
                                            y: clamp(node.y() / stageHeight, 0, 1)
                                        }));
                                    }}
                                />
                            )}

                            {isDrawing && draftDoodlePoints.length >= 4 && (
                                <Line
                                    points={draftDoodlePoints.map((point, pointIndex) => (
                                        pointIndex % 2 === 0 ? point * stageWidth : point * stageHeight
                                    ))}
                                    stroke={doodleColor}
                                    strokeWidth={doodleSize}
                                    lineCap="round"
                                    lineJoin="round"
                                    tension={0.12}
                                />
                            )}
                        </Layer>
                    </Stage>
                )}
            </div>

            {wallError && (
                <div className="freedom-wall-error-toast">{wallError}</div>
            )}

            <div className="freedom-wall-footer">
                <span>{sortedItems.length} items this week</span>
                <span>
                    {createItemMutation.isPending || updateItemMutation.isPending || deleteItemMutation.isPending
                        ? "Syncing..."
                        : "Synced"}
                </span>
            </div>
        </div>
    );
};

