  48→const sortItemsByZIndex = (items = []) => [...items].sort((a, b) => {
  49→    const zDiff = (a?.z_index || 0) - (b?.z_index || 0);
  50→    if(zDiff !== 0){
  51→        return zDiff;
  52→    }
  53→
  54→    const dateDiff = new Date(a?.created_at || 0) - new Date(b?.created_at || 0);
  55→    if(dateDiff !== 0){
  56→        return dateDiff;
  57→    }
  58→
  59→    return String(a?.id || "").localeCompare(String(b?.id || ""));
  60→});
  61→
  62→const upsertById = (items = [], nextItem) => {
  63→    const existingIndex = items.findIndex((item) => String(item?.id) === String(nextItem?.id));
  64→    if(existingIndex === -1){
  65→        return [...items, nextItem];
  66→    }
  67→
  68→    const nextItems = [...items];
  69→    const previousItem = nextItems[existingIndex];
  70→    nextItems[existingIndex] = {
  71→        ...previousItem,
  72→        ...nextItem,
  73→        payload: {
  74→            ...(previousItem?.payload || {}),
  75→            ...(nextItem?.payload || {})
  76→        },
  77→        users: nextItem?.users || previousItem?.users || null
  78→    };
  79→    return nextItems;
  80→};
