  84→const emojiCanvasCache = new Map();
  85→
  86→const useEmojiImage = (emoji, resolution = 128) => {
  87→    const [image, setImage] = useState(() => emojiCanvasCache.get(`${emoji}-${resolution}`) || null);
  88→
  89→    useEffect(() => {
  90→        if(!emoji){
  91→            setImage(null);
  92→            return;
  93→        }
  94→
  95→        const cacheKey = `${emoji}-${resolution}`;
  96→        const cached = emojiCanvasCache.get(cacheKey);
  97→        if(cached){
  98→            setImage(cached);
  99→            return;
 100→        }
 101→
 102→        const canvas = document.createElement("canvas");
 103→        canvas.width = resolution;
 104→        canvas.height = resolution;
 105→        const ctx = canvas.getContext("2d");
 106→        ctx.clearRect(0, 0, resolution, resolution);
 107→        ctx.textAlign = "center";
 108→        ctx.textBaseline = "middle";
 109→        ctx.font = `${Math.round(resolution * 0.78)}px "Segoe UI Emoji", "Apple Color Emoji", "Noto Color Emoji", sans-serif`;
 110→        ctx.fillText(emoji, resolution / 2, resolution / 2);
 111→
 112→        const img = new window.Image();
 113→        img.onload = () => {
 114→            emojiCanvasCache.set(cacheKey, img);
 115→            setImage(img);
 116→        };
 117→        img.src = canvas.toDataURL();
 118→    }, [emoji, resolution]);
 119→
 120→    return image;
 121→};
