 345→const PuffEffect = ({x, y, id, onComplete}) => {
 346→    const [progress, setProgress] = useState(0);
 347→    const startRef = useRef(null);
 348→    const particlesRef = useRef(null);
 349→
 350→    if(!particlesRef.current){
 351→        const count = 6 + Math.floor(Math.random() * 3);
 352→        particlesRef.current = Array.from({length: count}, () => ({
 353→            angle: Math.random() * Math.PI * 2,
 354→            distance: 30 + Math.random() * 20,
 355→            color: Math.random() > 0.5 ? "#a21caf" : "#e879f9"
 356→        }));
 357→    }
 358→
 359→    useEffect(() => {
 360→        const duration = 500;
 361→        let animId;
 362→
 363→        const animate = (timestamp) => {
 364→            if(!startRef.current) startRef.current = timestamp;
 365→            const elapsed = timestamp - startRef.current;
 366→            const p = Math.min(elapsed / duration, 1);
 367→            setProgress(p);
 368→
 369→            if(p < 1){
 370→                animId = requestAnimationFrame(animate);
 371→            } else {
 372→                onComplete(id);
 373→            }
 374→        };
 375→
 376→        animId = requestAnimationFrame(animate);
 377→        return () => cancelAnimationFrame(animId);
 378→    }, [id, onComplete]);
 379→
 380→    const particles = particlesRef.current;
 381→    const eased = 1 - Math.pow(1 - progress, 2);
 382→
 383→    return (
 384→        <Group x={x} y={y} listening={false}>
 385→            <Circle
 386→                radius={eased * 28}
 387→                stroke="#e879f9"
 388→                strokeWidth={Math.max(0.5, 2 * (1 - progress))}
 389→                opacity={1 - progress}
 390→            />
 391→            {particles.map((p, i) => (
 392→                <Circle
 393→                    key={i}
 394→                    x={Math.cos(p.angle) * p.distance * eased}
 395→                    y={Math.sin(p.angle) * p.distance * eased}
 396→                    radius={Math.max(0.5, 3.5 * (1 - progress))}
 397→                    fill={p.color}
 398→                    opacity={1 - progress}
 399→                />
 400→            ))}
 401→        </Group>
 402→    );
 403→};
