1506→                                const canEditItem = Boolean(
1507→                                    currentUserId &&
1508→                                    String(item?.user_id) === String(currentUserId) &&
1509→                                    activeTool !== "stamp"
1510→                                );
1511→                                const isSelected = String(selectedItemId) === String(item?.id);
