1513→                                    if(activeTool === "stamp"){
1514→                                        return;
1515→                                    }
1516→                                    setSelectedItemId(item.id);
1517→                                };
1518→
1519→                                if(item?.item_type === "doodle"){
1520→                                    const points = Array.isArray(item?.payload?.points)
1521→                                        ? item.payload.points
1522→                                            .map((point) => Number(point))
1523→                                            .filter((point) => !Number.isNaN(point))
