1614→
1615→                            {draftStamp && (
1616→                                <StampNode
1617→                                    item={{payload: draftStamp}}
1618→                                    stageWidth={stageWidth}
1619→                                    stageHeight={stageHeight}
1620→                                    canEdit={true}
1621→                                    isSelected={false}
1622→                                    isDraft={true}
1623→                                    onSelect={() => {}}
1624→                                    onDragEnd={(event) => {
1625→                                        const node = event?.target;
1626→                                        if(!node) return;
1627→                                        setDraftStamp((prev) => ({
1628→                                            ...prev,
1629→                                            x: clamp(node.x() / stageWidth, 0, 1),
1630→                                            y: clamp(node.y() / stageHeight, 0, 1)
1631→                                        }));
1632→                                    }}
1633→                                />
1634→                            )}
1635→
1636→                            {draftNote && (
1637→                                <NoteNode
1638→                                    item={{payload: draftNote}}
